solution_code:
#include <iostream>
#include <string>
#include <vector>

int add_ints(int a, int b) noexcept {
    return a + b;
}

int main() {
    std::cout << std::boolalpha;
    int sel;
    std::cin >> sel;
    if (sel == 1) {
        std::cout << "int add: " << noexcept(add_ints(0, 0)) << "\n";
    } else if (sel == 2) {
        std::vector<int> v;
        std::cout << "vector push: " << noexcept(v.push_back(0)) << "\n";
    } else {
        std::string s;
        std::cout << "string move: " << noexcept(std::string(std::move(s))) << "\n";
    }
    return 0;
}

